def minimax(node, is_maximizing):
    if isinstance(node, int):
        return node
    if is_maximizing:
        best = -999
        for child in node:
            best = max(best, minimax(child, False))
        return best
    else:
        best = 999
        for child in node:
            best = min(best, minimax(child, True))
        return best

tree = [[8, 1], [6, 4], [2, 3]]
print("Root value:", minimax(tree, True))

